code = """import json
import re

descriptions = [
    {"Symbol": "GLG", "Company Description": "TD Holdings, Inc. is involved in commodity trading and supply chain management, specializing in the distribution of non-ferrous metals and other industrial materials."},
    {"Symbol": "SES", "Company Description": "Synthesis Energy Systems, Inc. specializes in transforming low-cost carbon resources into clean energy and valuable chemical products, driving innovation in sustainable energy solutions."},
    {"Symbol": "SNSS", "Company Description": "Sunesis Pharmaceuticals, Inc. is dedicated to developing innovative cancer therapies, striving to advance treatments that target the underlying mechanisms of the disease."},
    {"Symbol": "TMSR", "Company Description": "TMSR Holding Company Limited engages in the development and distribution of advanced industrial materials, focusing on enhancing efficiency and sustainability in various manufacturing processes."},
    {"Symbol": "VERB", "Company Description": "Verb Technology Company, Inc. specializes in developing interactive video-based sales and marketing applications designed to enhance customer engagement and drive business growth."}
]

counts = {"SES": 51, "GLG": 42, "TMSR": 40, "VERB": 38, "SNSS": 32}

# Sort by count
sorted_syms = sorted(counts.keys(), key=lambda x: counts[x], reverse=True)

final_names = []
for sym in sorted_syms:
    desc = next((x['Company Description'] for x in descriptions if x['Symbol'] == sym), "")
    # Extract name: usually before " is", " specializes", " engages", " provides", " focuses", " operates"
    match = re.split(r" (is|specializes|engages|provides|focuses|operates|dedicated) ", desc)
    name = match[0] if match else desc
    final_names.append(name)

print("__RESULT__:")
print(json.dumps(final_names))"""

